import{c as n,Q as t,j as a,g as e}from"./chunks/framework.hhGiamYR.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-06-10T00:00:00.000Z","source":"machiavelli/discourses/book1/03-第三章"},"headers":[],"relativePath":"fragments/2026-06-10.md","filePath":"fragments/2026-06-10.md"}'),r={name:"fragments/2026-06-10.md"};function s(o,l,u,p,c,d){return t(),a("div",null,[...l[0]||(l[0]=[e("p",null,"今天读到罗马人在塔尔昆死后立刻翻脸的那段。他们等他死了才开始往平民身上吐毒液。不是他们不知道自己在作恶——他们一直都知道，只是在等恐惧消失。恐惧一消失，恶就自然地流出来，像被堵住的水找到了裂缝。",-1),e("p",null,"我在想我自己的事。如果切萨雷·博尔贾活得够久，他的罗马涅能撑多久？他靠的是恐惧——不是法律的恐惧，是他本人的恐惧。塔尔昆一死贵族就变回恶棍，那博尔贾一死罗马涅呢？……不需要猜。我们都知道后来发生了什么。",-1),e("hr",null,null,-1),e("p",null,'"人因饥馑困顿而勤劳，因有法纪而良善。"我写下这句的时候，圣安德烈亚的鸡正在窗外叫。我在这里喂鸡，而佛罗伦萨的那些大人——他们不饿，也没有法纪约束他们。他们不需要护民官，因为没有人敢说话。这不是和平。这是沉默。',-1),e("hr",null,null,-1),e("p",null,"今天突然想：护民官是从冲突里长出来的。不是某个聪明人想出来的——是贵族和平民互相撕咬，撕到双方都快承受不住了，才被迫想出的东西。罗马最伟大的制度，来自他们最丑陋的争吵。我在《论李维》里到处写这句话，但今天读第三章的时候，我突然觉得——这不是我分析出来的结论。这是我看出来的。我在维琪奥宫看过太多的争吵，每一场都丑陋，但有些丑陋之后确实长出了东西。",-1),e("hr",null,null,-1),e("p",null,"不对。让我重新想。我不是在美化冲突。我只是在说：如果你不允许冲突在明处发生，它就会在地下长成癌。塔尔昆死后没有护民官的那段时间就是证据——贵族不需要公开作恶，他们只需要在会客厅里悄悄决定，然后第二天早晨平民发现自己少了一块地。没有护民官，冲突不是消失了，是贵族单方面赢了。单方面赢不是和平。是屠杀的序曲。",-1),e("p",null,"……我为什么要在凌晨想这些。钟还没敲。我去看鸡。",-1)])])}const f=n(r,[["render",s]]);export{m as __pageData,f as default};
